import{_ as a,o as t,c as b,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"镇狱伏魔杀","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/镇狱伏魔杀.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/镇狱伏魔杀.md"}'),o={name:"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/镇狱伏魔杀.md"};function d(_,e,l,p,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"镇狱伏魔杀",tabindex:"-1"},[n("镇狱伏魔杀 "),r("a",{class:"header-anchor",href:"#镇狱伏魔杀","aria-label":'Permalink to "镇狱伏魔杀"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌037")])])],-1),s('<h1 id="镇狱伏魔杀-1" tabindex="-1">镇狱伏魔杀 <a class="header-anchor" href="#镇狱伏魔杀-1" aria-label="Permalink to &quot;镇狱伏魔杀&quot;">​</a></h1><p>镇狱伏魔杀.封<br> 本质：特异本质<br> 价格：B+2000<br> 分类：重剑<br> 体积：9<br> 武器伤害：23L<br> 描述：镇狱伏魔杀是一把用经历过天罚之百年精灵躯体为手柄，精巧工匠百炼地脉之铁为剑身，内含机妙之机关，此物价值不可以凡人话语衡量！<br> “说人话！”<br> ”自制电棍，雷击木手柄，螺纹钢剑身，按这里能放电，不接受讲价。“<br> 武器属性：【重型武器】【双手】【破甲5】<br> 武器特性：【狱外劫】【解封】<br> 【狱外劫】：镇狱伏魔杀具有【能量武器】特性，可造成雷击伤害。在选择造成雷击伤害时可以在周围的空气中明显看到蓝色电弧，同时雷电将击穿敌人的盔甲，具有【接触攻击】特性，且在攻击命中后附加2点雷击伤害。<br> 镇狱伏魔杀并没有明确的能量来源，但其却能无限供给能量，只要使用者心意一动，便能在按下剑柄的放电按钮的情况下随意控制放出的电流大小，形成浪漫的景象。</p><p>【解封】：在携带镇狱伏魔杀.封经历一场影片后，可在主神空间再支付B+2000为镇狱伏魔杀进行解封，此时【镇狱伏魔杀.封】更名为【镇狱伏魔杀.印】，视为A级武器。</p><p>镇狱伏魔杀.印<br> 本质：特异本质<br> 分类：重剑<br> 体积：9<br> 武器伤害：36L<br> 描述：天雷动，万物落，宿业缠身者，皆死。<br> “你，你做了什么，我的半身为何没有成为精魂，他本该复生于此！”<br> “建国以后不准成精。”<br> 武器属性：【重型武器】【双手】【破甲5】<br> 武器特性：【狱外劫】【斩精怪】<br> 【狱外劫】：镇狱伏魔杀具有【能量武器】特性，可造成雷击伤害。在选择造成雷击伤害时可以在周围的空气中明显看到蓝色电弧，同时雷电将击穿敌人的盔甲，具有【接触攻击】特性，且在攻击命中后附加2点雷击伤害。<br> 镇狱伏魔杀并没有明确的能量来源，但其却能无限供给能量，只要使用者心意一动，便能在按下剑柄的放电按钮的情况下随意控制放出的电流大小，形成浪漫的景象。<br> 【斩精怪】：镇狱伏魔杀完全解放出其难以解释的本质，其造成的伤害极其难以恢复，即使恢复也会留下深深的黑色疤痕，这实际上是目标陷入了时空来源的S级【重伤】状态，持续一个场景。被你击杀的单位如果具有的复活效果等级不大于S级，则无效该效果，这是一个A级时空来源的禁止复活效果。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
